import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import Footer from './Footer'; // ✅ ADDED

export default function Contact() {
  const [form, setForm] = useState({ name: '', email: '', message: '' });
  const [sent, setSent] = useState(false);
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e) {
    e.preventDefault();
    setLoading(true);

    try {
      const res = await fetch("http://localhost:5000/api/contact", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });

      const data = await res.json();

      if (data.success) {
        setSent(true);
        setForm({ name: '', email: '', message: '' });
      } else {
        alert("Failed to send message");
      }
    } catch (err) {
      alert("Server error");
    }

    setLoading(false);
  }

  return (
    <div style={{ background: 'var(--bg-base)', color: 'var(--text-primary)' }}>

      <nav style={{ padding: 20, display: 'flex', justifyContent: 'space-between' }}>
        <Link to="/">StudentBridge</Link>
        <div style={{ display: 'flex', gap: 15 }}>
          <Link to="/about">About</Link>
          <Link to="/login">Login</Link>
        </div>
      </nav>

      <div style={{ maxWidth: 560, margin: '100px auto', padding: 24 }}>
        <h1>Contact Us</h1>

        {sent ? (
          <div className="alert alert-success" style={{ padding: 20 }}>
            Message sent successfully!
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="card" style={{ padding: 24, borderRadius: 12 }}>

            <input
              placeholder="Name"
              value={form.name}
              onChange={e => setForm({ ...form, name: e.target.value })}
              required
            />

            <input
              placeholder="Email"
              value={form.email}
              onChange={e => setForm({ ...form, email: e.target.value })}
              required
            />

            <textarea
              placeholder="Message"
              value={form.message}
              onChange={e => setForm({ ...form, message: e.target.value })}
              required
            />

            <button disabled={loading} className="btn btn-primary">
              {loading ? "Sending..." : "Send"}
            </button>
          </form>
        )}
      </div>

      <Footer />
    </div>
  );
}
